#!/usr/bin/env node
/**
 * generate-noauth-schema.js
 *
 * Reads apps/dt-ws/schema/schema.graphql and produces
 * apps/dt-ws/schema/schema-noauth.graphql with all @authentication
 * directives stripped.
 *
 * Used for demo / development mode where OIDC is not configured.
 * The generated file MUST NOT be shipped in production images.
 *
 * Usage (from oss/ root):
 *   node scripts/generate-noauth-schema.js
 */

const fs = require('fs');
const path = require('path');

// Resolve paths relative to the oss/ root (parent of scripts/)
const OSS_ROOT = path.join(__dirname, '..');
const SCHEMA_DIR = path.join(OSS_ROOT, 'apps', 'dt-ws', 'schema');
const INPUT = path.join(SCHEMA_DIR, 'schema.graphql');
const OUTPUT = path.join(SCHEMA_DIR, 'schema-noauth.graphql');

const HEADER = [
  '# AUTO-GENERATED — DO NOT EDIT',
  '# Source: schema.graphql with @authentication directives removed.',
  '# Generated by: scripts/generate-noauth-schema.js',
  '#',
  '# This file is for demo / development use ONLY.',
  '# It MUST NOT be included in production Docker images.',
  '',
].join('\n');

function stripAuthentication(schema) {
  // Pattern 1: @authentication on type definitions (inline with other directives)
  //   e.g. "type Folder implements Element @authentication @node {"
  //   →    "type Folder implements Element @node {"
  let result = schema.replace(/ @authentication(?=[ \n{@])/g, '');

  // Pattern 2: standalone @authentication on its own line (mutations/queries)
  //   e.g. "    ): Model\n    @authentication"
  //   Remove the line entirely (including leading whitespace and trailing newline)
  result = result.replace(/^[ \t]*@authentication[ \t]*\n/gm, '');

  return result;
}

// --- main ---
try {
  const source = fs.readFileSync(INPUT, 'utf8');
  const stripped = stripAuthentication(source);
  fs.writeFileSync(OUTPUT, HEADER + stripped, 'utf8');

  // Quick sanity: the generated schema must NOT contain @authentication
  if (stripped.includes('@authentication')) {
    // Allow mentions inside comments (lines starting with #)
    const nonCommentLines = stripped
      .split('\n')
      .filter(l => !l.trimStart().startsWith('#'));
    const remaining = nonCommentLines.filter(l => l.includes('@authentication'));
    if (remaining.length > 0) {
      console.error(
        'WARNING: @authentication still present in non-comment lines:',
      );
      remaining.forEach(l => console.error('  ', l.trim()));
      process.exit(1);
    }
  }

  console.log(`Generated ${path.relative(process.cwd(), OUTPUT)}`);
} catch (err) {
  console.error('Failed to generate noauth schema:', err.message);
  process.exit(1);
}
